def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. When all triples share the same subject, the
    subject is mentioned once and the rest are expressed as descriptive clauses.
    Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to format numbers without unnecessary decimal point
    def _fmt(num: str) -> str:
        try:
            f = float(num)
            if f.is_integer():
                return str(int(f))
            return str(f)
        except ValueError:
            return num

    # Determine if all subjects are identical
    subjects = {t.subject for t in triples}
    if len(subjects) == 1:
        subject = triples[0].subject
        descriptors: list[str] = []

        for t in triples:
            p = t.predicate
            o = _fmt(_clean(t.object))

            if p == "cityServed":
                descriptors.append(f"serving the city of {o}")
            elif p == "location":
                descriptors.append(f"located in {o}")
            elif p == "country":
                descriptors.append(f"in {o}")
            elif p == "isPartOf":
                descriptors.append(f"part of {o}")
            elif p == "elevationAboveTheSeaLevel":
                descriptors.append(f"at an elevation of {o} metres above sea level")
            elif p == "elevationAboveTheSeaLevelInFeet":
                descriptors.append(f"at an elevation of {o} feet above sea level")
            elif p == "operatingOrganisation":
                descriptors.append(f"operated by {o}")
            elif p == "runwaySurfaceType":
                descriptors.append(f"with a runway surface of {o}")
            elif p.endswith("RunwayLengthFeet"):
                idx = p.split("Runway")[0].lower()
                descriptors.append(f"with its {idx} runway {o} feet long")
            elif p.endswith("RunwayLengthMetre"):
                idx = p.split("Runway")[0].lower()
                descriptors.append(f"with its {idx} runway {o} metres long")
            elif p == "runwayName":
                descriptors.append(f"whose runway is named {o}")
            elif p == "runwayLength":
                descriptors.append(f"with a runway length of {o} metres")
            elif p == "iataLocationIdentifier":
                descriptors.append(f"identified by IATA code {o}")
            elif p == "icaoLocationIdentifier":
                descriptors.append(f"identified by ICAO code {o}")
            elif p == "locationIdentifier":
                descriptors.append(f"identified by location code {o}")
            elif p == "owner":
                descriptors.append(f"owned by {o}")
            elif p == "leader":
                descriptors.append(f"led by {o}")
            elif p == "capital":
                descriptors.append(f"whose capital is {o}")
            elif p == "language":
                descriptors.append(f"where the language is {o}")
            else:
                descriptors.append(f"{p} {o}")

        # Build the complex sentence
        if len(descriptors) == 1:
            sentence = f"{subject} is {descriptors[0]}."
        else:
            # Join with commas and an 'and' before the last descriptor
            body = ", ".join(descriptors[:-1])
            body += f", and {descriptors[-1]}"
            sentence = f"{subject} {body}."
        return sentence[0].upper() + sentence[1:]
    else:
        # Fallback: treat each triple independently as before
